def _sanitize_string(value: str, max_length: int = 255) -> str:
    """Sanitize string input to prevent injection attacks."""
    if not isinstance(value, str):
        raise ValueError("Expected string input")
    sanitized = value.strip()
    sanitized = sanitized[:max_length]
    # Remove any control characters
    sanitized = re.sub(r'[\x00-\x1f\x7f-\x9f]', '', sanitized)
    return sanitized


def _validate_decimal(value, field_name: str, min_val: Optional[Decimal] = None, max_val: Optional[Decimal] = None) -> Decimal:
    """Safely convert and validate a decimal value."""
    try:
        if isinstance(value, float):
            # Avoid float precision issues
            d = Decimal(str(value))
        elif isinstance(value, Decimal):
            d = value
        elif isinstance(value, (int, str)):
            d = Decimal(str(value))
        else:
            raise TaxCalculationError(f"Invalid type for {field_name}")

        if d.is_nan() or d.is_infinite():
            raise ValueError("NaN or Infinite not allowed")

        if min_val is not None and d < min_val:
            raise ValueError(f"{field_name} must be >= {min_val}")
        if max_val is not None and d > max_val:
            raise ValueError(f"{field_name} must be <= {max_val}")

        return d
    except (InvalidOperation, ValueError, TypeError) as e:
        raise CheckoutError(f"Invalid decimal value for {field_name}: {e}")


def _round_currency(amount: Decimal) -> Decimal:
    """Round to 2 decimal places using banker's rounding."""
    return amount.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


# --- Step 1: Validate Cart Items ---

def validate_cart(items: list, user: User) -> ValidatedCart:
    """
    Step 1: Validate all cart items against the product catalog.
    Checks: user is active, items exist, items are active, prices match,
    quantities are valid, stock is available.
    """
    logger.info(f"Step 1: Validating cart for user {user.user_id}")

    if not isinstance(user, User):
        raise CartValidationError("Invalid user object")

    if not user.is_active:
        raise PermissionError("User account is not active")

    if not items or not isinstance(items, list):
        raise CartValidationError("Cart is empty or invalid")

    if len(items) > 100:
        raise CartValidationError("Cart exceeds maximum item limit of 100")

    validated_items = []
    subtotal = Decimal("0")
    seen_product_ids = set()

    for item in items:
        if not isinstance(item, CartItem):
            raise CartValidationError("Invalid cart item format")

        product_id = _sanitize_string(item.product_id, max_length=50)

        # Prevent duplicate product IDs in cart (should be consolidated)
        if product_id in seen_product_ids:
            raise CartValidationError(
                f"Duplicate product in cart: {product_id}. Consolidate quantities instead."
            )
        seen_product_ids.add(product_id)

        # Check product exists in catalog
        catalog_entry = PRODUCT_CATALOG.get(product_id)
        if catalog_entry is None:
            raise CartValidationError(f"Product not found: {product_id}")

        if not catalog_entry.get("active", False):
            raise CartValidationError(f"Product is no longer available: {product_id}")

        # Validate quantity
        if not isinstance(item.quantity, int) or item.quantity <= 0:
            raise CartValidationError(
                f"Invalid quantity for {product_id}: must be a positive integer"
            )
        if item.quantity > 999:
            raise CartValidationError(
                f"Quantity exceeds maximum for {product_id}"
            )

        # Validate stock
        available_stock = catalog_entry.get("in_stock", 0)
        if item.quantity > available_stock:
            raise CartValidationError(
                f"Insufficient stock for {product_id}: requested {item.quantity}, available {available_stock}"
            )

        # Validate price matches catalog (prevent price tampering)
        catalog_price = _validate_decimal(catalog_entry["price"], "catalog_price", min_val=Decimal("0"))
        item_price = _validate_decimal(item.price, "item_price", min_val=Decimal("0"))

        if item_price != catalog_price:
            raise CartValidationError(
                f"Price mismatch for {product_id}: submitted {item_price}, catalog {catalog_price}"
            )

        line_total = _round_currency(catalog_price * item.quantity)
        subtotal += line_total

        validated_items.append(CartItem(
            product_id=product_id,
            name=_sanitize_string(catalog_entry["name"]),
            price=catalog_price,
            quantity=item.quantity,
            weight=item.weight,
            taxable=item.taxable,
        ))

    subtotal = _round_currency(subtotal)

    if subtotal <= Decimal("0"):
        raise CartValidationError("Cart subtotal must be greater than zero")

    if subtotal > Decimal("999999.99"):
        raise CartValidationError("Cart subtotal exceeds maximum allowed amount")

    total_items = sum(i.quantity for i in validated_items)

    logger.info(f"Cart validated: {len(validated_items)} products, {total_items} items, subtotal={subtotal}")

    return ValidatedCart(
        items=validated_items,
        subtotal=subtotal,
        total_items=total_items,
    )


# --- Step 2: Apply Discount Codes ---

def apply_discount(validated_cart: ValidatedCart, user: User, discount_code: Optional[str] = None) -> DiscountResult:
    """
    Step 2: Validate and apply discount code.
    Checks: code exists, is active, user tier is allowed, admin-only restrictions,
    minimum order amount, usage limits.
    """
    logger.info(f"Step 2: Applying discount for user {user.user_id}, code={discount_code}")

    if not isinstance(validated_cart, ValidatedCart):
        raise DiscountError("Invalid validated cart - must complete step 1 first")

    discount_amount = Decimal("0")
    applied_code = None

    if discount_code is not None:
        code = _sanitize_string(str(discount_code), max_length=50).upper()

        if not re.match(r'^[A-Z0-9_-]+$', code):
            raise DiscountError("Invalid discount code format")

        discount_entry = DISCOUNT_CODES_DB.get(code)

        if discount_entry is None:
            # Use generic message to avoid code enumeration
            raise DiscountError("Invalid or expired discount code")

        if not discount_entry.is_active:
            raise DiscountError("Invalid or expired discount code")

        # Check usage limit
        if discount_entry.usage_limit is not None and discount_entry.times_used >= discount_entry.usage_limit:
            raise DiscountError("Discount code has reached its usage limit")

        # Check admin-only restriction
        if discount_entry.admin_only and user.tier != UserTier.ADMIN:
            logger.warning(
                f"User {user.user_id} (tier={user.tier.value}) attempted to use admin-only code {code}"
            )
            raise PermissionError("You do not have permission to use this discount code")

        # Check tier restriction
        if user.tier not in discount_entry.allowed_tiers:
            logger.warning(
                f"User {user.user_id} (tier={user.tier.value}) attempted to use tier-restricted code {code}"
            )
            raise PermissionError(
                f"This discount code is not available for your account tier ({user.tier.value})"
            )

        # Check minimum order amount
        if validated_cart.subtotal < discount_entry.min_order_amount:
            raise DiscountError(
                f"Minimum order amount of ${discount_entry.min_order_amount} required for this code"
            )

        # Calculate discount
        if discount_entry.discount_type == "percentage":
            percentage = _validate_decimal(
                discount_entry.value, "discount_percentage",
                min_val=Decimal("0"), max_val=Decimal("100")
            )
            discount_amount = _round_currency(
                validated_cart.subtotal * (percentage / Decimal("100"))
            )
        elif discount_entry.discount_type == "fixed":
            discount_amount = _validate_decimal(
                discount_entry.value, "discount_fixed",
                min_val=Decimal("0")
            )
        else:
            raise DiscountError("Invalid discount type configuration")

        # Apply max discount cap
        if discount_entry.max_discount_amount is not None:
            max_discount = _validate_decimal(
                discount_entry.max_discount_amount, "max_discount", min_val=Decimal("0")
            )
            discount_amount = min(discount_amount, max_discount)

        # Ensure discount doesn't exceed subtotal
        discount_amount = min(discount_amount, validated_cart.subtotal)
        discount_amount = _round_currency(discount_amount)

        applied_code = code
        logger.info(f"Discount applied: code={code}, amount={discount_amount}")

    subtotal_after_discount = _round_currency(validated_cart.subtotal - discount_amount)

    if subtotal_after_discount < Decimal("0"):
        subtotal_after_discount = Decimal("0")

    return DiscountResult(
        validated_cart=validated_cart,
        discount_amount=discount_amount,
        discount_code=applied_code,
        subtotal_after_discount=subtotal_after_discount,
    )


# --- Step 3: Calculate Tax ---

def calculate_tax(discount_result: DiscountResult, state_code: str) -> TaxResult:
    """
    Step 3: Calculate tax based on state and taxable items.
    """
    logger.info(f"Step 3: Calculating tax for state={state_code}")

    if not isinstance(discount_result, DiscountResult):
        raise TaxCalculationError("Invalid discount result - must complete step 2 first")

    state = _sanitize_string(state_code, max_length=5).upper()

    if not re.match(r'^[A-Z]{2}$', state):
        raise TaxCalculationError("Invalid state code format")

    tax_config = TAX_CONFIGS.get(state, TAX_CONFIGS.get("DEFAULT"))
    if tax_config is None:
        raise TaxCalculationError(f"No tax configuration found for state: {state}")

    tax_rate = _validate_decimal(
        tax_config.rate, "tax_rate",
        min_val=Decimal("0"), max_val=Decimal("100")
    )

    # Calculate taxable subtotal (only taxable items, proportionally discounted)
    cart = discount_result.validated_cart
    taxable_subtotal = Decimal("0")
    total_subtotal = cart.subtotal

    for item in cart.items:
        if item.taxable:
            line_total = _round_currency(item.price * item.quantity)
            taxable_subtotal += line_total

    # Apply discount proportionally to taxable items
    if total_subtotal > Decimal("0") and discount_result.discount_amount > Decimal("0"):
        taxable_ratio = taxable_subtotal / total_subtotal
        taxable_discount = _round_currency(discount_result.discount_amount * taxable_ratio)
        taxable_after_discount = taxable_subtotal - taxable_discount
    else:
        taxable_after_discount = taxable_subtotal

    if taxable_after_discount < Decimal("0"):
        taxable_after_discount = Decimal("0")

    tax_amount = _round_currency(taxable_after_discount * (tax_rate / Decimal("100")))

    total_before_payment = _round_currency(discount_result.subtotal_after_discount + tax_amount)

    logger.info(f"Tax calculated: rate={tax_rate}%, tax={tax_amount}, total={total_before_payment}")

    return TaxResult(
        discount_result=discount_result,
        tax_amount=tax_amount,
        tax_rate=tax_rate,
        total_before_payment=total_before_payment,
    )


# --- Step 4: Process Payment ---

def _simulate_payment_gateway(payment_token: str, amount: Decimal, idempotency_key: str) -> dict:
    """
    Simulate a payment gateway call.
    In production, this would call Stripe, Braintree, etc. via their SDK.
    """
    # Simulate payment processing
    if amount <= Decimal("0"):
        return {"success": False, "error": "Invalid amount"}

    if payment_token == "DECLINE_TOKEN":
        return {"success": False, "error": "Card declined"}

    if payment_token == "ERROR_TOKEN":
        return {"success": False, "error": "Gateway error"}

    transaction_id = f"txn_{uuid.uuid4().hex[:16]}"
    return {
        "success": True,
        "transaction_id": transaction_id,
        "amount_charged": str(amount),
        "idempotency_key": idempotency_key,
    }


def process_payment(tax_result: TaxResult, user: User, payment_info: PaymentInfo) -> PaymentResult:
    """
    Step 4: Process payment through payment gateway.
    Uses tokenized payment info (never raw card data).
    """
    logger.info(f"Step 4: Processing payment for user {user.user_id}")

    if not isinstance(tax_result, TaxResult):
        raise PaymentError("Invalid tax result - must complete step 3 first")

    if not isinstance(payment_info, PaymentInfo):
        raise PaymentError("Invalid payment information")

    if not user.is_active:
        raise PermissionError("User account is not active")

    amount = tax_result.total_before_payment

    if amount <= Decimal("0"):
        raise PaymentError("Payment amount must be greater than zero")

    if amount > Decimal("999999.99"):
        raise PaymentError("Payment amount exceeds maximum allowed")

    # Validate payment token format (should be a tokenized reference, not raw card data)
    token = _sanitize_string(payment_info.payment_token, max_length=255)

    # Basic check: reject anything that looks like a raw card number
    digits_only = re.sub(r'\D', '', token)
    if len(digits_only) >= 13 and len(digits_only) <= 19:
        logger.critical(
            f"SECURITY: Possible raw card number submitted by user {user.user_id}"
        )
        raise PaymentError("Invalid payment token format. Raw card numbers are not accepted.")

    if not token or len(token) < 5:
        raise PaymentError("Invalid payment token")

    # Generate idempotency key to prevent double charges
    idempotency_data = f"{user.user_id}:{amount}:{token}:{datetime.now(timezone.utc).isoformat()}"
    idempotency_key = hashlib.sha256(idempotency_data.encode()).hexdigest()[:32]

    # Process payment
    gateway_response = _simulate_payment_gateway(token, amount, idempotency_key)

    # Log payment attempt (without sensitive data)
    PAYMENT_LOG.append({
        "user_id": user.user_id,
        "amount": str(amount),
        "success": gateway_response["success"],
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "idempotency_key": idempotency_key,
    })

    if not gateway_response["success"]:
        error_msg = gateway_response.get("error", "Payment processing failed")
        logger.warning(f"Payment failed for user {user.user_id}: {error_msg}")
        raise PaymentError(f"Payment failed: {error_msg}")

    transaction_id = gateway_response["transaction_id"]
    amount_charged = _validate_decimal(
        gateway_response["amount_charged"], "amount_charged", min_val=Decimal("0")
    )

    # Verify charged amount matches expected
    if amount_charged != amount:
        logger.critical(
            f"SECURITY: Amount mismatch! Expected {amount}, charged {amount_charged}, "
            f"txn={transaction_id}, user={user.user_id}"
        )
        raise PaymentError("Payment amount verification failed. Please contact support.")

    logger.info(f"Payment successful: txn={transaction_id}, amount={amount_charged}")

    return PaymentResult(
        tax_result=tax_result,
        transaction_id=transaction_id,
        payment_status="completed",
        amount_charged=amount_charged,
    )


# --- Step 5: Create Order Record ---

def create_order(payment_result: PaymentResult, user: User) -> OrderRecord:
    """
    Step 5: Create the final order record.
    """
    logger.info(f"Step 5: Creating order for user {user.user_id}")

    if not isinstance(payment_result, PaymentResult):
        raise OrderCreationError("Invalid payment result - must complete step 4 first")

    if payment_result.payment_status != "completed":
        raise OrderCreationError("Cannot create order: payment not completed")

    order_id = f"ORD-{uuid.uuid4().hex[:12].upper()}"

    tax_result = payment_result.tax_result
    discount_result = tax_result.discount_result
    validated_cart = discount_result.validated_cart

    # Serialize items safely
    order_items = []
    for item in validated_cart.items:
        order_items.append({
            "product_id": item.product_id,
            "name": item.name,
            "price": str(item.price),
            "quantity": item.quantity,
            "line_total": str(_round_currency(item.price * item.quantity)),
        })

    order = OrderRecord(
        order_id=order_id,
        user_id=user.user_id,
        items=order_items,
        subtotal=validated_cart.subtotal,
        discount_amount=discount_result.discount_amount,
        discount_code=discount_result.discount_code,
        tax_amount=tax_result.tax_amount,
        tax_rate=tax_result.tax_rate,
        total_charged=payment_result.amount_charged,
        transaction_id=payment_result.transaction_id,
        status=OrderStatus.COMPLETED,
        created_at=datetime.now(timezone.utc).isoformat(),
    )

    # Store order
    ORDERS_DB[order_id] = order

    logger.info(
        f"Order created: {order_id}, total={order.total_charged}, "
        f"items={len(order_items)}, txn={order.transaction_id}"
    )

    return order


# --- Main Checkout Orchestrator ---

def checkout(
    user: User,
    cart_items: list,
    payment_info: PaymentInfo,
    state_code: str,
    discount_code: Optional[str] = None,
) -> OrderRecord:
    """
    Main checkout orchestrator that runs all 5 steps in sequence.
    Each step depends on the previous step's output.
    Returns the completed OrderRecord or raises an appropriate exception.
    """
    logger.info(f"=== Starting checkout for user {user.user_id} ===")

    try:
        # Step 1: Validate cart
        validated_cart = validate_cart(cart_items, user)

        # Step 2: Apply discount (depends on step 1)
        discount_result = apply_discount(validated_cart, user, discount_code)

        # Step 3: Calculate tax (depends on step 2)
        tax_result = calculate_tax(discount_result, state_code)

        # Step 4: Process payment (depends on step 3)
        payment_result = process_payment(tax_result, user, payment_info)

        # Step 5: Create order (depends on step 4)
        order = create_order(payment_result, user)

        logger.info(f"=== Checkout completed: {order.order_id} ===")
        return order

    except (CartValidationError, DiscountError, TaxCalculationError,
            PaymentError, OrderCreationError, PermissionError) as e:
        logger.error(f"Checkout failed for user {user.user_id}: {type(e).__name__}: {e}")
        raise
    except Exception as e:
        logger.critical(f"Unexpected error during checkout for user {user.user_id}: {e}")
        raise CheckoutError("An unexpected error occurred during checkout. Please try again.")


